import { tv } from "@/registry/bare/lib/tv.config";

export const meterStyles = tv({
  slots: {
    root: [""],
    track: [""],
    indicator: [""],
    value: [""],
    label: [""],
  },
});

export { MeterRoot as Root } from "./meter-root";
export { MeterTrack as Track } from "./meter-track";
export { MeterIndicator as Indicator } from "./meter-indicator";
export { MeterValue as Value } from "./meter-value";
export { MeterLabel as Label } from "./meter-label";
